SELECT 
FROM biz_dish
WHERE is_deleted = 0
AND merchant_id = #{merchantId}
AND category_id = #{categoryId}
AND status = #{status}

    AND name LIKE CONCAT('%', #{keyword}, '%')

ORDER BY sales DESC, rating DESC

mapper.update:
UPDATE biz_dish
name = #{name}, price = #{price}, original_price = #{originalPrice}, image = #{image}, description = #{description}, stock = #{stock}, sales = #{sales}, rating = #{rating}, status = #{status}, update_time = NOW()
WHERE id = #{id}
